    33→
    34→/**
    35→ * {@code ConsumerDelegateCreator} implements a quasi-factory pattern to allow the caller to remain unaware of the
    36→ * underlying {@link Consumer} implementation that is created. This provides the means by which {@link KafkaConsumer}
    37→ * can remain the top-level facade for implementations, but allow different implementations to co-exist under
    38→ * the covers.
    39→ *
    40→ * <p/>
    41→ *
    42→ * The current logic for the {@code ConsumerCreator} inspects the incoming configuration and determines if
    43→ * it is using the new consumer group protocol (KIP-848) or if it should fall back to the existing, legacy group
    44→ * protocol. This is based on the presence and value of the {@link ConsumerConfig#GROUP_PROTOCOL_CONFIG group.protocol}
    45→ * configuration. If the value is present and equal to &quot;{@code consumer}&quot;, the {@link AsyncKafkaConsumer}
    46→ * will be returned. Otherwise, the {@link ClassicKafkaConsumer} will be returned.
    47→ *
    48→ *
    49→ * <p/>
    50→ *
    51→ * <em>Note</em>: this is for internal use only and is not intended for use by end users. Internal users should
    52→ * not attempt to determine the underlying implementation to avoid coding to an unstable interface. Rather, it is
    53→ * the {@link Consumer} API contract that should serve as the caller's interface.
    54→ */
    55→public class ConsumerDelegateCreator {
    56→
    57→    public <K, V> ConsumerDelegate<K, V> create(ConsumerConfig config,
    58→                                                Deserializer<K> keyDeserializer,
    59→                                                Deserializer<V> valueDeserializer) {
    60→        try {
    61→            GroupProtocol groupProtocol = GroupProtocol.valueOf(config.getString(ConsumerConfig.GROUP_PROTOCOL_CONFIG).toUpperCase(Locale.ROOT));
    62→
    63→            if (groupProtocol == GroupProtocol.CONSUMER)
    64→                return new AsyncKafkaConsumer<>(config, keyDeserializer, valueDeserializer, Optional.empty());
    65→            else
    66→                return new ClassicKafkaConsumer<>(config, keyDeserializer, valueDeserializer);
    67→        } catch (KafkaException e) {
    68→            throw e;
    69→        } catch (Throwable t) {
    70→            throw new KafkaException("Failed to construct Kafka consumer", t);
    71→        }
    72→    }
    73→
    74→    public <K, V> ConsumerDelegate<K, V> create(LogContext logContext,
    75→                                                Time time,
    76→                                                ConsumerConfig config,
    77→                                                Deserializer<K> keyDeserializer,
    78→                                                Deserializer<V> valueDeserializer,
    79→                                                KafkaClient client,
    80→                                                SubscriptionState subscriptions,
    81→                                                ConsumerMetadata metadata,
